1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Damage = { itemType: string; amount: number };
7	type Incident = { cause: string; damages: Damage[] };
8	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
9	type Step = QuoteStep | ClaimStep;
10	type Scenario = { customer: Customer; steps: Step[] };
11	type QuoteResult = { premium: number };
12	type ClaimResult = { payout: number; remainingCap: number };
13	type StepResult = QuoteResult | ClaimResult;
14	type ScenarioResult = { results: StepResult[] };
15	
16	type ItemSpec = { basePrice: number; insuranceValue: number };
17	
18	const ITEM_CATALOG: Record<string, ItemSpec> = {
19	  sword: { basePrice: 100, insuranceValue: 1000 },
20	  amulet: { basePrice: 60, insuranceValue: 600 },
21	  staff: { basePrice: 80, insuranceValue: 800 },
22	  potion: { basePrice: 40, insuranceValue: 400 },
23	  rune: { basePrice: 25, insuranceValue: 250 },
24	  moonstone: { basePrice: 25, insuranceValue: 250 },
25	};
26	
27	const specOf = (item: Item): ItemSpec | undefined => ITEM_CATALOG[item.type];
28	
29	const basePriceOf = (item: Item): number => specOf(item)?.basePrice ?? 0;
30	
31	const CURSED_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	
35	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
36	
37	const isCursed = (item: Item): boolean => item.cursed === true;
38	const isHighlyEnchanted = (item: Item): boolean =>
39	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
40	
41	const surchargeRate = (item: Item): number =>
42	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
43	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
44	
45	const itemSurchargeAmount = (item: Item): number =>
46	  basePriceOf(item) * surchargeRate(item);
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	const BLOCK_SIZE = 3;
50	const BLOCK_PRICE = 60;
51	
52	const groupItemsByType = (items: Item[]): Item[][] => {
53	  const groups = new Map<string, Item[]>();
54	  for (const item of items) {
55	    const existing = groups.get(item.type) ?? [];
56	    existing.push(item);
57	    groups.set(item.type, existing);
58	  }
59	  return Array.from(groups.values());
60	};
61	
62	const qualifiesForComponentBlock = (members: Item[]): boolean =>
63	  members.length === BLOCK_SIZE && COMPONENT_TYPES.has(members[0].type);
64	
65	const sumOf = <T>(items: T[], valueOf: (item: T) => number): number =>
66	  items.reduce((total, item) => total + valueOf(item), 0);
67	
68	const sumBasePrices = (items: Item[]): number => sumOf(items, basePriceOf);
69	
70	const groupBasePremium = (members: Item[]): number =>
71	  qualifiesForComponentBlock(members) ? BLOCK_PRICE : sumBasePrices(members);
72	
73	const itemsBaseSubtotal = (items: Item[]): number =>
74	  sumOf(groupItemsByType(items), groupBasePremium);
75	
76	const itemsSurchargeSubtotal = (items: Item[]): number =>
77	  sumOf(items, itemSurchargeAmount);
78	
79	const LOYALTY_DISCOUNT_RATE = 0.2;
80	const LOYALTY_YEARS_THRESHOLD = 2;
81	
82	const isLoyalCustomer = (customer: Customer): boolean =>
83	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
84	
85	const loyaltyDiscountRate = (customer: Customer): number =>
86	  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;
87	
88	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
89	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
90	
91	const hasPreviousContract = (stepIndex: number): boolean => stepIndex > 0;
92	
93	const followUpDiscountRate = (stepIndex: number): number =>
94	  hasPreviousContract(stepIndex) ? FOLLOW_UP_DISCOUNT_RATE : 0;
95	
96	const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
97	  FIRST_INSURANCE_SURCHARGE_RATE -
98	  loyaltyDiscountRate(customer) -
99	  followUpDiscountRate(stepIndex);
100	
101	// Kept as `base + base*rate` (not `base*(1+rate)`) for IEEE-754 stability:
102	// e.g. 100*(1+0.1) === 110.00000000000001, which trips Math.ceil rounding.
103	const adjustedBasePremium = (baseSubtotal: number, rate: number): number =>
104	  baseSubtotal + baseSubtotal * rate;
105	
106	const quotePremium = (
107	  items: Item[],
108	  customer: Customer,
109	  stepIndex: number,
110	): number =>
111	  adjustedBasePremium(
112	    itemsBaseSubtotal(items),
113	    policyAdjustmentRate(customer, stepIndex),
114	  ) +
115	  itemsSurchargeSubtotal(items) +
116	  PROCESSING_FEE;
117	
118	// MHPCO always rounds in its own favor: premiums up, payouts down.
119	const roundPremiumInMhpcoFavor = (amount: number): number => Math.ceil(amount);
120	const roundPayoutInMhpcoFavor = (amount: number): number => Math.floor(amount);
121	
122	const insuranceValueOf = (item: Item): number =>
123	  specOf(item)?.insuranceValue ?? 0;
124	
125	const DEDUCTIBLE_PER_DAMAGE = 100;
126	const CAP_MULTIPLIER = 2;
127	
128	const insuranceSum = (items: Item[]): number =>
129	  sumOf(items, insuranceValueOf);
130	
131	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
132	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
133	
134	const isHighEnchantmentForPayout = (item: Item): boolean =>
135	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
136	
137	const reimbursableAmount = (damage: Damage, item: Item): number =>
138	  isHighEnchantmentForPayout(item)
139	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
140	    : damage.amount;
141	
142	const damagePayout = (damage: Damage, item: Item): number =>
143	  reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE;
144	
145	// The CLI rejects claims for items not on the policy upstream, so the lookup
146	// is total over the inputs that reach this function.
147	const policyItemOfType = (policyItems: Item[], itemType: string): Item =>
148	  policyItems.find((item) => item.type === itemType) as Item;
149	
150	const totalPayout = (damages: Damage[], policyItems: Item[]): number =>
151	  sumOf(damages, (damage) =>
152	    damagePayout(damage, policyItemOfType(policyItems, damage.itemType)),
153	  );
154	
155	const policyCap = (policyItems: Item[]): number =>
156	  CAP_MULTIPLIER * insuranceSum(policyItems);
157	
158	const isKnownItem = (item: Item): boolean => specOf(item) !== undefined;
159	
160	const validateItemTypes = (items: Item[]): void => {
161	  const unknown = items.find((item) => !isKnownItem(item));
162	  if (unknown !== undefined) {
163	    throw new Error(`unknown item type '${unknown.type}'`);
164	  }
165	};
166	
167	const runQuoteStep = (
168	  step: QuoteStep,
169	  customer: Customer,
170	  stepIndex: number,
171	): QuoteResult => {
172	  validateItemTypes(step.items);
173	  return {
174	    premium: roundPremiumInMhpcoFavor(
175	      quotePremium(step.items, customer, stepIndex),
176	    ),
177	  };
178	};
179	
180	const settleClaim = (
181	  step: ClaimStep,
182	  policyItems: Item[],
183	  availableCap: number,
184	): ClaimResult => {
185	  const uncappedPayout = roundPayoutInMhpcoFavor(
186	    totalPayout(step.incident.damages, policyItems),
187	  );
188	  const payout = Math.min(uncappedPayout, availableCap);
189	  return { payout, remainingCap: availableCap - payout };
190	};
191	
192	// Claim steps reference a prior quote step by index; the CLI guarantees that
193	// reference is valid and points at a quote, so the lookup is total.
194	const policyItemsAt = (steps: Step[], policyIndex: number): Item[] =>
195	  (steps[policyIndex] as QuoteStep).items;
196	
197	const countOccurrences = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> => {
198	  const counts = new Map<string, number>();
199	  for (const item of items) {
200	    const key = keyOf(item);
201	    counts.set(key, (counts.get(key) ?? 0) + 1);
202	  }
203	  return counts;
204	};
205	
206	const validateDamagesAgainstPolicy = (
207	  damages: Damage[],
208	  policyItems: Item[],
209	): void => {
210	  const remainingSlots = countOccurrences(policyItems, (item) => item.type);
211	  for (const damage of damages) {
212	    const slotsLeft = remainingSlots.get(damage.itemType) ?? 0;
213	    if (slotsLeft === 0) {
214	      throw new Error(
215	        `claim references more '${damage.itemType}' damages than the policy covers`,
216	      );
217	    }
218	    remainingSlots.set(damage.itemType, slotsLeft - 1);
219	  }
220	};
221	
222	const settleClaimAgainstPolicyCap = (
223	  step: ClaimStep,
224	  steps: Step[],
225	  remainingCaps: Map<number, number>,
226	): ClaimResult => {
227	  const policyItems = policyItemsAt(steps, step.policy);
228	  validateDamagesAgainstPolicy(step.incident.damages, policyItems);
229	  const availableCap = remainingCaps.get(step.policy) ?? policyCap(policyItems);
230	  const result = settleClaim(step, policyItems, availableCap);
231	  remainingCaps.set(step.policy, result.remainingCap);
232	  return result;
233	};
234	
235	const runStep = (
236	  step: Step,
237	  customer: Customer,
238	  stepIndex: number,
239	  steps: Step[],
240	  remainingCaps: Map<number, number>,
241	): StepResult =>
242	  step.op === "quote"
243	    ? runQuoteStep(step, customer, stepIndex)
244	    : settleClaimAgainstPolicyCap(step, steps, remainingCaps);
245	
246	export const runScenario = (input: Scenario): ScenarioResult => {
247	  const remainingCaps = new Map<number, number>();
248	  return {
249	    results: input.steps.map((step, i) =>
250	      runStep(step, input.customer, i, input.steps, remainingCaps),
251	    ),
252	  };
253	};
